from decimal import Decimal, ROUND_HALF_EVEN, InvalidOperation

def parse_monto(texto: str):
    t = texto.strip()
    if t == "":
        return False, None, f"ERROR en 'monto': vacío (raw={texto!r})"
    try:
        mon = Decimal(t).quantize(Decimal("0.01"), rounding=ROUND_HALF_EVEN)
        return True, mon, None
    except InvalidOperation:
        return False, None, f"ERROR en 'monto': no se pudo parsear {texto!r}"

for s in ["150.50", "  20.1 ", "", "abc"]:
    print(repr(s), "→", parse_monto(s))

def simular_input(nombres: str, contacto: str, edad: str) -> dict:
    datos = {"nombres": nombres, "contacto": contacto, "edad": edad}
    return {
        **datos,
        "types": {k: type(v).__name__ for k, v in datos.items()},
    }

